/* eslint-disable camelcase */
/* eslint-disable no-undef */

/**
 * @typedef {Object} DisableWebviewTopbarProps
 * @prop {() => void} onBack
 * @prop {number} [opacity]
 * @prop {boolean} [animated]
 * @prop {number} [duration]
 */

/**
 * @typedef {Object} SubscriptionIds
 * @prop {any} [backActionSubscriptionId]
 */

/**
 * @typedef {Object} EnableWebviewTopbarProps
 * @prop {boolean} [animated]
 * @prop {number} [duration]
 * @prop {SubscriptionIds} [subscriptionIds]
 */

const isValidWebkitEnvironment = () => (
  typeof MobileWebKit !== 'undefined'
  && typeof MobileWebKit.executeNative === 'function'
  && typeof MobileWebKit.events !== 'undefined'
  && typeof MobileWebKit.events.subscribeMethod === 'function'
  && typeof MobileWebKit.events.unsubscribe === 'function'
);

const isWebkit2 = () => (
  isValidWebkitEnvironment()
  && MobileWebKit?.engine === MobileWebKit?.Engines?.V200
);

/** @param {DisableWebviewTopbarProps} props */
const disableWebviewTopbar = ({
  onBack,
  opacity = 0.8,
  animated = true,
  duration = 200,
}) => {
  if (!isWebkit2()) return;
  MobileWebKit?.topbar.disable({ opacity, animated, duration }).catch(() => {});

  const backActionSubscriptionId = MobileWebKit?.navigation.subscribeToBackAction(onBack);

  return { backActionSubscriptionId };
};

/** @param {EnableWebviewTopbarProps} props */
const enableWebviewTopbar = ({
  animated = true,
  duration = 200,
  subscriptionIds,
} = {}) => {
  if (!isWebkit2()) return;
  MobileWebKit?.topbar.enable({ animated, duration }).catch(() => {});

  if (subscriptionIds?.backActionSubscriptionId) {
    MobileWebKit?.navigation.unsubscribeToBackAction(subscriptionIds.backActionSubscriptionId).catch(() => {});
  }
};

/** @param {DisableWebviewTopbarProps} props */
const hideWebviewTopbar = ({
  onBack,
  animated = true,
  duration: animation_duration = 350,
}) => {
  if (!isWebkit2()) return;

  if (typeof MobileWebKit?.topbar?.fullScreenMode === 'function') {
    MobileWebKit.topbar.fullScreenMode(true, { animated, animation_duration }).catch(() => {});
  } else {
    MobileWebKit?.topbar.disable({ opacity: 0.8, animated, duration: 200 }).catch(() => {});
  }

  const backActionSubscriptionId = MobileWebKit?.navigation.subscribeToBackAction(onBack);

  return { backActionSubscriptionId };
};

/** @param {EnableWebviewTopbarProps} props */
const showWebviewTopbar = ({
  animated = true,
  duration: animation_duration = 350,
  subscriptionIds,
} = {}) => {
  if (!isWebkit2()) return;

  if (typeof MobileWebKit?.topbar?.fullScreenMode === 'function') {
    MobileWebKit.topbar.fullScreenMode(false, { animated, animation_duration }).catch(() => {});
  } else {
    MobileWebKit?.topbar.enable({ animated, duration: 200 }).catch(() => {});
  }

  if (subscriptionIds?.backActionSubscriptionId) {
    MobileWebKit?.navigation.unsubscribeToBackAction(subscriptionIds.backActionSubscriptionId).catch(() => {});
  }
};

export { disableWebviewTopbar, enableWebviewTopbar, hideWebviewTopbar, showWebviewTopbar };
